mapper.select:
SELECT COUNT(*)
FROM alert
WHERE alert_type = #{alertType}
AND product_id = #{productId}

    AND inventory_lot_id = #{inventoryLotId}


    AND inventory_lot_id IS NULL

AND created_at >= TRUNC(SYSDATE)

mapper.insert:
INSERT INTO alert_detail (alert_id, dept_id, emp_id, role_code, is_read, is_delivered) SELECT #{alertId}, e.dept_id, e.emp_id, e.role_code, 'N', 'N' FROM employee e
JOIN department d ON d.dept_id=e.dept_id
AND d.dept_code=#{deptCode}
AND e.role_code=#{roleCode}
AND NOT EXISTS( SELECT 1 FROM alert_detail ad WHERE ad.alert_id=#{alertId} AND ad.emp_id=e.emp_id )

mapper.select:
SELECT e.emp_id, e.role_code, d.dept_id, d.dept_code
FROM employee e
JOIN department d
ON e.dept_id = d.dept_id
WHERE d.dept_code=#{deptCode}

    AND e.role_code=#{roleCode}

mapper.update:
UPDATE alert_detail
SET is_read='Y'
WHERE alert_id = #{alertId}
  AND emp_id = #{empId}

UPDATE alert_detail
SET is_delivered='Y'
WHERE alert_id = #{alertId}
  AND emp_id = #{empId}
